import React, { useState, useEffect } from 'react';
import { CheckCircle, XCircle, AlertTriangle, ArrowLeft } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { formatDisplayDate } from '../../utils/dateUtils';

interface Return {
  id: string;
  venta_id: string;
  tipo_devolucion: 'total' | 'parcial';
  monto_devolucion: number;
  razon: string;
  estado: 'pendiente' | 'aprobada' | 'rechazada';
  usuario: {
    nombre_completo: string;
  };
  creado_en: string;
  detalles: {
    id: string;
    detalle_venta_id: string;
    cantidad_devuelta: number;
    precio_unitario: number;
    producto: {
      nombre: string;
    };
  }[];
}

interface ReturnApprovalModalProps {
  isOpen: boolean;
  onClose: () => void;
  returnId: string;
  onSuccess: () => void;
}

const ReturnApprovalModal: React.FC<ReturnApprovalModalProps> = ({ isOpen, onClose, returnId, onSuccess }) => {
  const { user } = useAuth();
  const [returnData, setReturnData] = useState<Return | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [rejectReason, setRejectReason] = useState('');
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [showRejectForm, setShowRejectForm] = useState(false);

  const fetchReturnDetails = React.useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      // Fetch return data
      const { data: returnData, error: returnError } = await supabase
        .from('devoluciones')
        .select(`
          *,
          usuario:usuario_id (nombre_completo)
        `)
        .eq('id', returnId)
        .single();

      if (returnError) throw returnError;

      // Fetch return details with product info
      const { data: detailsData, error: detailsError } = await supabase
        .from('detalle_devoluciones')
        .select(`
          *,
          producto:detalle_ventas!inner(
            producto:producto_id(nombre)
          )
        `)
        .eq('devolucion_id', returnId);

      if (detailsError) throw detailsError;

      // Format details data
      const formattedDetails = detailsData.map((detail: any) => ({
        id: detail.id,
        detalle_venta_id: detail.detalle_venta_id,
        cantidad_devuelta: detail.cantidad_devuelta,
        precio_unitario: detail.precio_unitario,
        producto: {
          nombre: detail.producto.producto.nombre
        }
      }));

      setReturnData({
        ...returnData,
        detalles: formattedDetails
      });
    } catch (err: unknown) {
      console.error('Error fetching return details:', err);
      const errorMessage = err instanceof Error ? err.message : 'Error desconocido';
      setError(`Error al cargar los detalles de la devoluci├│n: ${errorMessage}`);
    } finally {
      setLoading(false);
    }
  }, [returnId]);

  useEffect(() => {
    if (isOpen && returnId) {
      fetchReturnDetails();
    }
  }, [isOpen, returnId, fetchReturnDetails]);

  const handleApprove = async () => {
    if (!user?.id) return;

    setIsSubmitting(true);
    setError(null);

    try {
      const { error } = await supabase
        .from('devoluciones')
        .update({
          estado: 'aprobada',
          aprobada_por: user.id,
          fecha_aprobacion: new Date().toISOString()
        })
        .eq('id', returnId);

      if (error) throw error;

      onSuccess();
      setSuccessMessage('Devoluci├│n aprobada correctamente. Se ha actualizado el stock y ajustado el saldo de la venta.');

      // Wait 2 seconds before closing to show success message
      setTimeout(() => {
        onClose();
      }, 2000);
    } catch (err: unknown) {
      console.error('Error approving return:', err);
      const errorMessage = err instanceof Error ? err.message : 'Error desconocido';
      setError(`Error al aprobar la devoluci├│n: ${errorMessage}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleReject = async () => {
    if (!rejectReason.trim()) {
      setError('Por favor, ingresa un motivo para rechazar la devoluci├│n');
      return;
    }

    setIsSubmitting(true);
    setError(null);

    try {
      const { error } = await supabase
        .from('devoluciones')
        .update({
          estado: 'rechazada',
          aprobada_por: user?.id,
          fecha_aprobacion: new Date().toISOString(),
          notas: rejectReason
        })
        .eq('id', returnId);

      if (error) throw error;

      onSuccess();
      setSuccessMessage('Devoluci├│n rechazada correctamente.');

      // Wait 2 seconds before closing to show success message
      setTimeout(() => {
        onClose();
      }, 2000);
    } catch (err: unknown) {
      console.error('Error rejecting return:', err);
      const errorMessage = err instanceof Error ? err.message : 'Error desconocido';
      setError(`Error al rechazar la devoluci├│n: ${errorMessage}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="flex items-center justify-center min-h-screen pt-4 px-4 pb-20 text-center sm:block sm:p-0">
        <div className="fixed inset-0 transition-opacity" onClick={onClose}>
          <div className="absolute inset-0 bg-gray-500 opacity-75"></div>
        </div>

        <div className="inline-block align-bottom bg-white rounded-lg text-left overflow-hidden shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-2xl sm:w-full">
          <div className="bg-white px-4 pt-5 pb-4 sm:p-6 sm:pb-4">
            <div className="sm:flex sm:items-start">
              <div className="mx-auto flex-shrink-0 flex items-center justify-center h-12 w-12 rounded-full bg-yellow-100 sm:mx-0 sm:h-10 sm:w-10">
                <ArrowLeft className="h-6 w-6 text-yellow-600" aria-hidden="true" />
              </div>
              <div className="mt-3 text-center sm:mt-0 sm:ml-4 sm:text-left w-full">
                <h3 className="text-lg font-medium text-gray-900">
                  Revisar Solicitud de Devoluci├│n
                </h3>
                {loading ? (
                  <div className="mt-4 flex justify-center">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
                  </div>
                ) : error ? (
                  <div className="mt-4 bg-red-50 border-l-4 border-red-400 p-4 rounded-md">
                    <div className="flex">
                      <div className="flex-shrink-0">
                        <AlertTriangle className="h-5 w-5 text-red-400" />
                      </div>
                      <div className="ml-3">
                        <p className="text-sm text-red-700">{error}</p>
                      </div>
                    </div>
                  </div>
                ) : returnData && (
                  <>
                  {successMessage && (
                    <div className="mb-4 bg-green-50 border-l-4 border-green-400 p-4 rounded-md">
                      <div className="flex">
                        <div className="flex-shrink-0">
                          <CheckCircle className="h-5 w-5 text-green-400" />
                        </div>
                        <div className="ml-3">
                          <p className="text-sm text-green-700">{successMessage}</p>
                        </div>
                      </div>
                    </div>
                  )}
                  <div className="mt-4 space-y-4">
                    <div className="bg-gray-50 p-4 rounded-md">
                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <p className="text-sm text-gray-500">Tipo de devoluci├│n</p>
                          <p className="text-sm font-medium text-gray-900 capitalize">
                            {returnData.tipo_devolucion}
                          </p>
                        </div>
                        <div>
                          <p className="text-sm text-gray-500">Monto a devolver</p>
                          <p className="text-sm font-medium text-gray-900">
                            ${returnData.monto_devolucion.toLocaleString()}
                          </p>
                        </div>
                        <div>
                          <p className="text-sm text-gray-500">Solicitado por</p>
                          <p className="text-sm font-medium text-gray-900">
                            {returnData.usuario.nombre_completo}
                          </p>
                        </div>
                        <div>
                          <p className="text-sm text-gray-500">Fecha de solicitud</p>
                          <p className="text-sm font-medium text-gray-900">
                            {formatDisplayDate(returnData.creado_en)}
                          </p>
                        </div>
                      </div>
                      <div className="mt-4">
                        <p className="text-sm text-gray-500">Motivo</p>
                        <p className="text-sm font-medium text-gray-900">
                          {returnData.razon}
                        </p>
                      </div>
                    </div>

                    <div>
                      <h4 className="text-sm font-medium text-gray-900 mb-2">
                        Productos a devolver
                      </h4>
                      <div className="border border-gray-200 rounded-md overflow-hidden">
                        <table className="min-w-full divide-y divide-gray-200">
                          <thead className="bg-gray-50">
                            <tr>
                              <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Producto
                              </th>
                              <th scope="col" className="px-4 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Cantidad
                              </th>
