import React, { useState, useEffect } from 'react';
import { ArrowLeft, CheckCircle, XCircle, AlertTriangle, Eye, RefreshCw } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { formatDisplayDate } from '../../utils/dateUtils';
import ReturnApprovalModal from './ReturnApprovalModal';

interface Return {
  id: string;
  venta_id: string;
  tipo_devolucion: string;
  monto_devolucion: number;
  razon: string;
  estado: 'pendiente' | 'aprobada' | 'rechazada';
  usuario: {
    nombre_completo: string;
  };
  creado_en: string;
}

interface ReturnsListModalProps {
  isOpen: boolean;
  onClose: () => void;
  saleId?: string;
}

const ReturnsListModal: React.FC<ReturnsListModalProps> = ({ isOpen, onClose, saleId }) => {
  const { user } = useAuth();
  const [returns, setReturns] = useState<Return[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedReturnId, setSelectedReturnId] = useState<string | null>(null);
  const [showApprovalModal, setShowApprovalModal] = useState(false);
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [refreshTrigger, setRefreshTrigger] = useState(0);

  useEffect(() => {
    if (isOpen && user?.negocioId) {
      fetchReturns();
    }
  }, [isOpen, user, saleId, statusFilter, refreshTrigger]);

  const fetchReturns = async () => {
    setLoading(true);
    setError(null);

    try {
      let query = supabase
        .from('devoluciones')
        .select(`
          *,
          usuario:usuario_id (nombre_completo)
        `)
        .eq('negocio_id', user?.negocioId);

      if (saleId) {
        query = query.eq('venta_id', saleId);
      }

      if (statusFilter !== 'all') {
        query = query.eq('estado', statusFilter);
      }

      query = query.order('creado_en', { ascending: false });

      const { data, error } = await query;

      if (error) throw error;
      setReturns(data || []);
    } catch (err: any) {
      console.error('Error fetching returns:', err);
      setError(`Error al cargar las devoluciones: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  const handleViewReturn = (returnId: string) => {
    setSelectedReturnId(returnId);
    setShowApprovalModal(true);
  };

  const handleRefresh = () => {
    setRefreshTrigger(prev => prev + 1);
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'pendiente':
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">
            <AlertTriangle className="h-3 w-3 mr-1" />
            Pendiente
          </span>
        );
      case 'aprobada':
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
            <CheckCircle className="h-3 w-3 mr-1" />
            Aprobada
          </span>
        );
      case 'rechazada':
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">
            <XCircle className="h-3 w-3 mr-1" />
            Rechazada
          </span>
        );
      default:
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
            {status}
          </span>
        );
    }
  };

  if (!isOpen) return null;

  return (
    <>
      <div className="fixed inset-0 z-50 overflow-y-auto">
        <div className="flex items-center justify-center min-h-screen pt-4 px-4 pb-20 text-center sm:block sm:p-0">
          <div className="fixed inset-0 transition-opacity" onClick={onClose}>
            <div className="absolute inset-0 bg-gray-500 opacity-75"></div>
          </div>

          <div className="inline-block align-bottom bg-white rounded-lg text-left overflow-hidden shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-3xl sm:w-full">
            <div className="bg-white px-4 pt-5 pb-4 sm:p-6 sm:pb-4">
              <div className="sm:flex sm:items-start">
                <div className="mx-auto flex-shrink-0 flex items-center justify-center h-12 w-12 rounded-full bg-blue-100 sm:mx-0 sm:h-10 sm:w-10">
                  <ArrowLeft className="h-6 w-6 text-blue-600" aria-hidden="true" />
                </div>
                <div className="mt-3 text-center sm:mt-0 sm:ml-4 sm:text-left w-full">
                  <h3 className="text-lg font-medium text-gray-900">
                    {saleId ? 'Devoluciones de esta venta' : 'Todas las devoluciones'}
                  </h3>

                  <div className="mt-4">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center">
                        <p className="text-sm text-gray-500 mr-2">
                          {returns.length} devoluciones encontradas
                        </p>
                        <button 
                          onClick={handleRefresh}
                          className="p-1 rounded-full hover:bg-gray-100 text-gray-500"
                          title="Actualizar"
                        >
                          <RefreshCw className="h-4 w-4" />
                        </button>
                      </div>

                      <select
                        className="focus:ring-primary-500 focus:border-primary-500 h-full py-0 pl-2 pr-7 border-gray-300 bg-white text-gray-500 sm:text-sm rounded-md"
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                      >
                        <option value="all">Todos los estados</option>
                        <option value="pendiente">Pendientes</option>
                        <option value="aprobada">Aprobadas</option>
                        <option value="rechazada">Rechazadas</option>
                      </select>
                    </div>

                    {loading ? (
                      <div className="flex justify-center py-8">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
                      </div>
                    ) : error ? (
                      <div className="bg-red-50 border-l-4 border-red-400 p-4">
                        <div className="flex">
                          <div className="flex-shrink-0">
                            <AlertTriangle className="h-5 w-5 text-red-400" />
                          </div>
                          <div className="ml-3">
                            <p className="text-sm text-red-700">{error}</p>
                          </div>
                        </div>
                      </div>
                    ) : returns.length === 0 ? (
                      <div className="text-center py-8">
                        <ArrowLeft className="h-12 w-12 text-gray-300 mx-auto mb-4" />
                        <p className="text-gray-500">No se encontraron devoluciones</p>
                        {statusFilter !== 'all' && (
                          <p className="text-sm text-gray-400 mt-2">
                            Prueba cambiando el filtro de estado
                          </p>
                        )}
                      </div>
                    ) : (
                      <div className="overflow-x-auto max-h-96">
                        <table className="min-w-full divide-y divide-gray-200">
                          <thead className="bg-gray-50 sticky top-0">
                            <tr>
                              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Fecha
                              </th>
                              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Solicitante
                              </th>
                              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Tipo
                              </th>
                              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Monto
                              </th>
                              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Estado
                              </th>
                              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                                Acciones
                              </th>
                            </tr>
                          </thead>
                          <tbody className="bg-white divide-y divide-gray-200">
                            {returns.map((returnItem) => (
                              <tr key={returnItem.id} className="hover:bg-gray-50">
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                                  {formatDisplayDate(returnItem.creado_en)}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                                  {returnItem.usuario.nombre_completo}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 capitalize">
                                  {returnItem.tipo_devolucion}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                                  ${returnItem.monto_devolucion.toLocaleString()}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap">
                                  {getStatusBadge(returnItem.estado)}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                  <button
                                    onClick={() => handleViewReturn(returnItem.id)}
                                    className="text-primary-600 hover:text-primary-900 p-1 rounded-full hover:bg-primary-50"
                                    title="Ver detalles"
                                  >
                                    <Eye className="h-5 w-5" />
                                  </button>
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-gray-50 px-4 py-3 sm:px-6 sm:flex sm:flex-row-reverse">
              <button
                type="button"
                className="w-full inline-flex justify-center rounded-md border border-gray-300 shadow-sm px-4 py-2 bg-white text-base font-medium text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500 sm:ml-3 sm:w-auto sm:text-sm"
                onClick={onClose}
              >
                Cerrar
              </button>
            </div>
          </div>
        </div>
      </div>

      {showApprovalModal && selectedReturnId && (
        <ReturnApprovalModal
          isOpen={showApprovalModal}
          onClose={() => setShowApprovalModal(false)}
          returnId={selectedReturnId}
          onSuccess={() => {
            handleRefresh();
            setShowApprovalModal(false);
          }}
        />
      )}
    </>
  );
};

export default ReturnsListModal;

import React, { useState, useEffect } from 'react';
import { AlertTriangle, ShieldAlert, AlertCircle, Info } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import type { Sale } from '../../types/sales';

interface SaleDeleteModalProps {
  isOpen: boolean;
  onClose: () => void;
  sale: Sale;
  onSuccess: () => void;
}

const SaleDeleteModal: React.FC<SaleDeleteModalProps> = ({ isOpen, onClose, sale, onSuccess }) => {
  const [isDeleting, setIsDeleting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [confirmText, setConfirmText] = useState('');

  useEffect(() => {
    if (isOpen) {
      setConfirmText('');
      setError(null);
      // Lock body scroll
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  if (!isOpen) return null;

  const handleDelete = async () => {
    if (confirmText.toUpperCase() !== 'ELIMINAR') {
      setError('Por favor, escribe "ELIMINAR" para confirmar');
      return;
    }

    setIsDeleting(true);
    setError(null);

    try {
      // The trigger handles related records, but we ensure clean deletion
      const { error: saleError } = await supabase
        .from('ventas')
        .delete()
        .eq('id', sale.id);

      if (saleError) throw saleError;

      onSuccess();
      onClose();
    } catch (err: any) {
      console.error('Error deleting sale:', err);
      setError(`Error al anular la venta: ${err.message}`);
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-0 sm:p-4 animate-in fade-in duration-300">
      <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-md" onClick={onClose} />

      <div className="relative w-full max-w-lg bg-white rounded-t-[2.5rem] sm:rounded-[3rem] shadow-2xl animate-in zoom-in slide-in-from-bottom duration-400 overflow-hidden">
        {/* Header de Riesgo */}
        <div className="bg-rose-50 p-8 pb-10 border-b border-rose-100 flex flex-col items-center text-center">
           <div className="h-20 w-20 rounded-[2rem] bg-rose-100 flex items-center justify-center text-rose-600 mb-6 shadow-inner ring-8 ring-rose-50">
              <ShieldAlert className="h-10 w-10 animate-pulse" />
           </div>

           <div className="flex items-center gap-2 mb-2">
              <span className="text-[10px] font-black text-rose-400 uppercase tracking-[0.3em]">Protocolo de Seguridad</span>
           </div>
           <h3 className="text-3xl font-black text-rose-900 font-outfit leading-none mb-3">Anular Operaci├│n</h3>
           <p className="text-rose-700/60 font-medium text-sm max-w-[280px]">Est├ís a punto de eliminar de forma permanente la Venta <span className="font-black text-rose-900">#{sale.id.slice(0, 8)}</span></p>
        </div>

        {/* Cuerpo del Modal */}
        <div className="p-8 space-y-6">
           <div className="space-y-4">
              <div className="flex items-start gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                 <div className="h-8 w-8 rounded-lg bg-white shadow-sm flex items-center justify-center text-rose-500 shrink-0 mt-1">
                    <AlertTriangle className="h-4 w-4" />
                 </div>
                 <div className="space-y-2">
                    <p className="text-xs font-black text-slate-800 uppercase tracking-tight">Impacto en el Sistema</p>
                    <ul className="space-y-1.5">
                       <li className="flex items-center gap-2 text-[11px] font-bold text-slate-500">
                          <div className="h-1 w-1 rounded-full bg-rose-400" /> Se eliminar├ín todos los pagos asociados
                       </li>
                       <li className="flex items-center gap-2 text-[11px] font-bold text-slate-500">
                          <div className="h-1 w-1 rounded-full bg-rose-400" /> El registro contable ser├í borrado permanentemente
                       </li>
                       <li className="flex items-center gap-2 text-[11px] font-bold text-slate-500 font-black text-rose-600">
                          <div className="h-1 w-1 rounded-full bg-rose-600" /> Esta acci├│n NO restaura el stock autom├íticamente
                       </li>
                    </ul>
                 </div>
              </div>

              <div className="space-y-3">
                 <div className="flex items-center justify-between px-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Confirmaci├│n Requerida</label>
                    <span className="text-[10px] font-bold text-rose-500 uppercase">Input Cr├¡tico</span>
                 </div>
                 <div className="relative group">
                    <input
                      type="text"
                      placeholder='Escribe "ELIMINAR" para proceder'
                      className={`w-full px-6 py-5 bg-slate-50 border-2 ${error ? 'border-rose-500' : 'border-slate-100'} rounded-[1.5rem] text-sm font-black uppercase tracking-widest text-slate-900 placeholder:text-slate-300 focus:outline-none focus:ring-4 focus:ring-slate-100 transition-all text-center`}
                      value={confirmText}
                      onChange={(e) => {
                        setConfirmText(e.target.value);
                        if (error) setError(null);
                      }}
                    />
                    {confirmText.toUpperCase() === 'ELIMINAR' && (
                       <div className="absolute right-6 top-1/2 -translate-y-1/2 animate-in zoom-in">
                          <AlertCircle className="h-5 w-5 text-emerald-500" />
                       </div>
                    )}
                 </div>
              </div>

              {error && (
                <div className="animate-in slide-in-from-top-2 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3">
                   <Info className="h-4 w-4 text-rose-500 shrink-0" />
                   <p className="text-xs font-black text-rose-700 uppercase">{error}</p>
                </div>
              )}
           </div>

           <div className="flex flex-col gap-3">
              <button
                onClick={handleDelete}
                disabled={isDeleting || confirmText.toUpperCase() !== 'ELIMINAR'}
                className="w-full py-5 bg-rose-600 text-white rounded-[1.8rem] text-xs font-black uppercase tracking-[0.2em] shadow-xl shadow-rose-200 hover:bg-rose-700 hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-40 disabled:scale-100 disabled:shadow-none"
              >
                {isDeleting ? 'Procesando Anulaci├│n...' : 'Confirmar Eliminaci├│n'}
              </button>
              <button
                onClick={onClose}
                disabled={isDeleting}
                className="w-full py-5 bg-white border-2 border-slate-50 text-slate-400 rounded-[1.8rem] text-xs font-black uppercase tracking-[0.2em] hover:bg-slate-50 hover:text-slate-600 transition-all font-outfit"
              >
                Cancelar Operaci├│n
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default SaleDeleteModal;

import React, { useState, useEffect } from 'react';
import { Edit3, X, AlertCircle, Calendar, FileText, Info, History } from 'lucide-react';
