  sale: Sale;
  onClose: () => void;
  onGeneratePDF: (sale: Sale) => void;
}

interface PartialPayment {
  id: string;
  monto: number;
  metodo_pago: string;
  fecha_pago: string;
  notas: string;
}

const SalePreviewModal: React.FC<SalePreviewModalProps> = ({ sale, onClose, onGeneratePDF }) => {
  const [returnInfo, setReturnInfo] = useState<{
    id: string;
    tipo_devolucion: string;
    monto_devolucion: number;
    estado: string;
    detalle_devoluciones: {
      detalle_venta_id: string;
      cantidad_devuelta: number;
    }[];
  } | null>(null);
  const [partialPayments, setPartialPayments] = useState<PartialPayment[]>([]);

  useEffect(() => {
    fetchReturnInfo();
    if (sale.metodo_pago === 'credito') {
      fetchPartialPayments();
    }
  }, [sale.id, sale.metodo_pago]);

  const fetchReturnInfo = async () => {
    try {
      const { data, error } = await supabase
        .from('devoluciones')
        .select(`
          id,
          tipo_devolucion,
          monto_devolucion,
          estado,
          detalle_devoluciones (
            detalle_venta_id,
            cantidad_devuelta
          )
        `)
        .eq('venta_id', sale.id)
        .eq('estado', 'aprobada')
        .maybeSingle();

      if (error) throw error;
      setReturnInfo(data);
    } catch (err) {
      console.error('Error fetching return info:', err);
    }
  };

  const fetchPartialPayments = async () => {
    try {
      const { data, error } = await supabase
        .from('pagos_parciales')
        .select('*')
        .eq('venta_id', sale.id)
        .order('fecha_pago', { ascending: false });

