    (doc as any).autoTable({
      startY: currentY + 5,
      body: ventasData,
      theme: 'plain'
    });

    currentY = (doc as any).lastAutoTable.finalY + 15;

    // Movimientos Detalles
    if (currentMovements.length > 0) {
      doc.setFontSize(14);
      doc.text('Detalle de Movimientos de Caja', 20, currentY);

      const movsData = currentMovements.map(m => [
