import React, { useState, useEffect } from 'react';
import { Search, UserPlus, Edit, Trash2, AlertCircle, CheckCircle, Shield, Key, Mail, User as UserIcon, X, Lock, Save, Briefcase, Building2 } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { useAuth } from '../contexts/AuthContext';

type User = {
  id: string;
  nombre_completo: string;
  correo: string;
  rol: 'propietario' | 'administrador' | 'cajero';
  creado_en: string;
  ultimo_acceso?: string;
};

type UserFormData = {
  nombre_completo: string;
  correo: string;
  rol: 'propietario' | 'administrador' | 'cajero';
  password?: string;
};

const Users: React.FC = () => {
  const { user } = useAuth();
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [roleFilter, setRoleFilter] = useState<string>('all');
  const [showModal, setShowModal] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isChangingPassword, setIsChangingPassword] = useState(false);

  const [formData, setFormData] = useState<UserFormData>({
    nombre_completo: '',
    correo: '',
    rol: 'cajero',
    password: ''
  });

  useEffect(() => {
    if (user?.negocioId) {
      fetchUsers();
    }
  }, [user]);

  // Clear messages after 5 seconds
  useEffect(() => {
    if (successMessage || error) {
      const timer = setTimeout(() => {
        setSuccessMessage(null);
        setError(null);
      }, 5000);
      return () => clearTimeout(timer);
    }
  }, [successMessage, error]);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('usuarios')
        .select('*')
        .eq('negocio_id', user?.negocioId)
        .order('creado_en', { ascending: false });

      if (error) throw error;
      setUsers(data || []);
    } catch (err: any) {
      console.error('Error fetching users:', err);
      setError('Error al cargar usuarios');
    } finally {
      setLoading(false);
    }
  };

  const handleEditClick = (u: User) => {
    setEditingUser(u);
    setFormData({
      nombre_completo: u.nombre_completo,
      correo: u.correo,
      rol: u.rol,
      password: ''
    });
    setIsChangingPassword(false);
    setShowModal(true);
  };

  const handleAddNew = () => {
    setEditingUser(null);
    setFormData({
      nombre_completo: '',
      correo: '',
      rol: 'cajero',
      password: ''
    });
    setIsChangingPassword(false);
    setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMessage(null);
    setIsSubmitting(true);

    try {
      if (editingUser) {
        // Update existing user profile in public.usuarios
        const { error: updateError } = await supabase
          .from('usuarios')
          .update({
            nombre_completo: formData.nombre_completo,
            rol: formData.rol
          })
          .eq('id', editingUser.id);

        if (updateError) throw updateError;

        // Update password if changing using RPC function
        if (isChangingPassword && formData.password) {
          const { error: rpcError } = await supabase.rpc('update_user_credentials', {
            p_user_id: editingUser.id,
            p_new_password: formData.password
          });

          if (rpcError) {
            console.error("RPC Error:", rpcError);
            throw new Error("Perfil actualizado, pero la contrase├▒a no se pudo cambiar. Requiere crear la funci├│n SQL de actualizaci├│n en Supabase.");
          }
        }

        setSuccessMessage('Usuario actualizado exitosamente');
      } else {
        // Create new user with auth
        const { data: authData, error: signUpError } = await supabase.auth.signUp({
          email: formData.correo,
          password: formData.password!,
          options: {
            data: {
              nombre_completo: formData.nombre_completo
            }
          }
        });

        if (signUpError) {
          if (signUpError.message.includes('rate limit')) {
            throw new Error("L├¡mite de correos en Supabase excedido. Por seguridad, deshabilita 'Confirm Email' en la configuraci├│n de Auth de Supabase.");
          }
          throw signUpError;
        }

        // Create user profile
        if (authData.user) {
          const { error: profileError } = await supabase
            .from('usuarios')
            .update({
              rol: formData.rol,
              negocio_id: user?.negocioId
            })
            .eq('id', authData.user.id);

          if (profileError) throw profileError;
        }
        setSuccessMessage('Usuario creado exitosamente');
      }

      await fetchUsers();
      setShowModal(false);
    } catch (err: any) {
      console.error('Error:', err);
      setError(err.message || "Ha ocurrido un error inesperado al procesar la solicitud.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (userId: string) => {
    try {
      const { error } = await supabase.auth.admin.deleteUser(userId);
      if (error) {
        if (error.message.includes('admin API')) {
          throw new Error("No es posible eliminar el usuario directamente desde esta interfaz por restricciones de seguridad. Por favor hazlo desde el panel de Supabase.");
        }
        throw error;
      }

      await fetchUsers();
      setDeleteConfirmId(null);
      setSuccessMessage('Usuario eliminado exitosamente');
    } catch (err: any) {
      console.error('Error deleting user:', err);
      setError(err.message || 'Error al eliminar usuario');
