    setError(null);

    try {
      // Determinar el rango de fechas seg├║n el modo
      const actualStartDate = dateMode === 'single' ? startDate : startDate;
      const actualEndDate = dateMode === 'single' ? startDate : endDate;

      // Fetch sales with product details for the selected period
      const { data: salesData, error: salesError } = await supabase
        .from('ventas')
        .select(`
          id,
          total,
          metodo_pago,
          creada_en,
          detalle_ventas (
            cantidad,
            precio_unitario,
            producto:producto_id (
              id,
              nombre,
              precio_costo,
              categoria_id,
              categorias:categoria_id (
                nombre
              )
            )
          )
        `)
        .eq('negocio_id', user?.negocioId)
        .gte('creada_en', startOfDay(actualStartDate).toISOString())
        .lte('creada_en', endOfDay(actualEndDate).toISOString())
        .eq('estado', 'pagada');

      if (salesError) throw salesError;

      // Calculate metrics
      let totalSales = 0;
      let totalCosts = 0;
      const productMetrics: Map<string, {
        name: string;
        revenue: number;
        cost: number;
        quantity: number;
      }> = new Map();

      const categoryMetrics: Map<string, {
        revenue: number;
        cost: number;
      }> = new Map();

      const paymentMethods: Map<string, number> = new Map();
      const dailyMetrics: Map<string, { revenue: number; cost: number }> = new Map();

      salesData?.forEach(sale => {
        totalSales += sale.total;

        // Payment method breakdown
        const currentAmount = paymentMethods.get(sale.metodo_pago) || 0;
        paymentMethods.set(sale.metodo_pago, currentAmount + sale.total);

        // Daily metrics
        const saleDate = format(new Date(sale.creada_en), 'yyyy-MM-dd');
        const dailyData = dailyMetrics.get(saleDate) || { revenue: 0, cost: 0 };
        dailyData.revenue += sale.total;

        sale.detalle_ventas.forEach(detail => {
          const productCost = detail.producto.precio_costo * detail.cantidad;
          const productRevenue = detail.precio_unitario * detail.cantidad;
          totalCosts += productCost;
          dailyData.cost += productCost;

          // Product metrics
          const existing = productMetrics.get(detail.producto.id) || {
            name: detail.producto.nombre,
            revenue: 0,
            cost: 0,
            quantity: 0
          };

          existing.revenue += productRevenue;
          existing.cost += productCost;
          existing.quantity += detail.cantidad;
          productMetrics.set(detail.producto.id, existing);

          // Category metrics
          const categoryName = detail.producto.categorias?.nombre || 'Sin categor├¡a';
          const categoryData = categoryMetrics.get(categoryName) || { revenue: 0, cost: 0 };
          categoryData.revenue += productRevenue;
          categoryData.cost += productCost;
          categoryMetrics.set(categoryName, categoryData);
        });

        dailyMetrics.set(saleDate, dailyData);
      });

      const profit = totalSales - totalCosts;
      const profitMargin = totalSales > 0 ? (profit / totalSales) * 100 : 0;

      // Convert to arrays and sort
      const topProducts = Array.from(productMetrics.values())
        .map(product => ({
          name: product.name,
          revenue: product.revenue,
          cost: product.cost,
          profit: product.revenue - product.cost,
          margin: product.revenue > 0 ? ((product.revenue - product.cost) / product.revenue) * 100 : 0,
          quantity: product.quantity
        }))
        .sort((a, b) => b.profit - a.profit)
        .slice(0, 10);

      const categoryProfits = Array.from(categoryMetrics.entries())
        .map(([category, data]) => ({
          category,
          profit: data.revenue - data.cost,
          margin: data.revenue > 0 ? ((data.revenue - data.cost) / data.revenue) * 100 : 0,
          revenue: data.revenue
        }))
        .sort((a, b) => b.profit - a.profit);

      const dailyProfits = Array.from(dailyMetrics.entries())
        .map(([date, data]) => ({
          date,
          revenue: data.revenue,
          cost: data.cost,
          profit: data.revenue - data.cost
        }))
        .sort((a, b) => a.date.localeCompare(b.date));

      const totalPayments = Array.from(paymentMethods.values()).reduce((sum, amount) => sum + amount, 0);
      const paymentMethodBreakdown = Array.from(paymentMethods.entries())
        .map(([method, amount]) => ({
          method,
          amount,
          percentage: totalPayments > 0 ? (amount / totalPayments) * 100 : 0
        }))
        .sort((a, b) => b.amount - a.amount);

      setMetrics({
        totalSales,
        totalCosts,
        profit,
        profitMargin,
        topProducts,
        dailyProfits,
        categoryProfits,
        paymentMethodBreakdown
      });
    } catch (err: any) {
      console.error('Error fetching utility metrics:', err);
      setError(err.message);
    } finally {
